def follower_reach(spec: dict) -> list:
    """Users reachable within two Follow hops of the target, sorted, excluding the target."""
    users = set(spec["users"])
    who = spec["who"]
    if who not in users:
        return []
    adj = {}
    for f in spec["follows"]:
